const input = $input.first().json || {};
const parseMaybeJson = (value) => {
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
};
const asObject = (value) => value && typeof value === 'object' && !Array.isArray(value) ? value : null;
const hasOwn = (value, key) => Object.prototype.hasOwnProperty.call(value || {}, key);
const looksLikeMetaPayload = (value) => {
  const obj = asObject(value);
  return !!obj && (obj.object === 'instagram' || obj.object === 'page' || (Array.isArray(obj.entry) && obj.entry.length > 0));
};
const looksLikeRelayEnvelope = (value) => {
  const obj = asObject(value);
  return !!obj && (hasOwn(obj, 'relay') || (hasOwn(obj, 'body') && (hasOwn(obj, 'headers') || hasOwn(obj, 'relay'))));
};

const inputObject = asObject(parseMaybeJson(input)) || {};
const level1 = asObject(parseMaybeJson(inputObject.body));
const level2 = asObject(parseMaybeJson(level1?.body));
const relayEnvelope = [inputObject, level1, level2].find(looksLikeRelayEnvelope) || null;
const relay = relayEnvelope?.relay ?? level2?.relay ?? level1?.relay ?? inputObject.relay ?? null;
const headers = relayEnvelope?.headers ?? level2?.headers ?? level1?.headers ?? inputObject.headers ?? null;
const bodyCandidates = [level2, parseMaybeJson(relayEnvelope?.body), level1, parseMaybeJson(inputObject.body), inputObject]
  .map((value) => parseMaybeJson(value))
  .filter((value) => value != null);
const parsedBody = bodyCandidates.find(looksLikeMetaPayload) || bodyCandidates.find((value) => asObject(value)) || bodyCandidates[0] || null;
const hasMetaEnvelope = Array.isArray(parsedBody?.entry) && parsedBody.entry.length > 0;
const isMetaPayload = looksLikeMetaPayload(parsedBody);
const relayValidated = [true, 'true', 1, '1'].includes(relay?.validated_by_api);
if (relayValidated && isMetaPayload) {
  return [{
    json: {
      ...inputObject,
      headers,
      relay,
      body: parsedBody
    }
  }];
}
if (isMetaPayload) {
  return [{
    json: {
      ...inputObject,
      headers,
      body: parsedBody,
      relay: {
        ...(relay || {}),
        source: relay?.source || 'meta-direct-to-n8n',
        channel: 'INSTAGRAM',
        validated_by_api: false,
        direct_compatibility_mode: true
      }
    }
  }];
}
throw new Error('Unsupported Instagram webhook payload. Expected NovaVision API relay or direct Meta payload.');

const body = $input.first().json.body || $input.first().json;
const entry = body?.entry?.[0] || {};
const messaging = entry?.messaging?.[0] || null;
if (!messaging || messaging?.message?.is_echo) {
  return [{ json: { is_supported_event: false, is_status_update: true } }];
}
const attachments = messaging.message?.attachments || [];
const firstAttachmentType = String(attachments[0]?.type || '').toLowerCase();
const typeMap = { image: 'IMAGE', audio: 'AUDIO', video: 'VIDEO', file: 'FILE', sticker: 'STICKER' };
const mappedType = attachments.length > 0 ? (typeMap[firstAttachmentType] || 'UNKNOWN') : 'TEXT';
const text = messaging.message?.text || messaging.postback?.title || messaging.quick_reply?.payload || '';
const channelAccountId = messaging.recipient?.id || entry?.id || body?.entry?.[0]?.id || null;
return [{
  json: {
    is_supported_event: Boolean(messaging.message || messaging.postback),
    is_status_update: false,
    channel: 'INSTAGRAM',
    provider: 'META',
    provider_message_id: messaging.message?.mid || messaging.postback?.mid || null,
    provider_parent_message_id: messaging.message?.reply_to?.mid || null,
    external_user_id: messaging.sender?.id || null,
    channel_account_id: channelAccountId,
    external_display_name: messaging.sender?.name || '',
    message_type: mappedType,
    event_type: 'MESSAGE',
    direction: 'INBOUND',
    text_body: text,
    normalized_text: (text || '').trim(),
    media_url: attachments[0]?.payload?.url || null,
    raw_payload: messaging,
    received_at: new Date(messaging.timestamp || Date.now()).toISOString()
  }
}];

const gates = $input.first().json || {};
const lastInboundAt = gates.last_inbound_at ? new Date(gates.last_inbound_at).getTime() : Date.now();
const within24h = (Date.now() - lastInboundAt) <= (24 * 60 * 60 * 1000);
let blockedBy = null;
if (gates.is_opted_out) blockedBy = 'opt_out';
else if (gates.human_handoff) blockedBy = 'human_handoff';
else if (!within24h) blockedBy = 'outside_24h_window';
else if (Number(gates.consecutive_bot_outbound || 0) >= 3) blockedBy = 'too_many_bot_outbound';
return [{ json: { ...gates, can_reply: !blockedBy, blocked_by: blockedBy } }];

const history = $node['Load Conversation Context'].json || [];
const historyArr = Array.isArray(history) ? history : [];
const inbound = $node['Parse Instagram Event'].json;
const chronologicalHistory = [...historyArr].reverse();
const historyText = chronologicalHistory.map(h => `${h.direction}: ${h.message_text}`).join('\n');
const botMessages = chronologicalHistory.filter(h => String(h.direction || '').toUpperCase() === 'BOT');
const lastBotMessage = botMessages.length ? String(botMessages[botMessages.length - 1].message_text || '') : '';
const builderUrl = 'https://novavision.lat/builder';
const priceRegex = /(precio|precios|cuanto sale|cuánto sale|cuanto cuesta|cuánto cuesta|costo|costos|tarifa|tarifas|plan|planes)/i;
const shortAffirmationRegex = /^(si|sí|dale|ok|oka|bueno|genial|perfecto|mandame|mándame|pasame|pasámelo|quiero|me interesa)\W*$/i;
const offeredPriceRegex = /(precio|precios|plan|planes|detalles|link para ver los planes|ver los planes)/i;
const offeredBuilderRegex = /(builder|crear tu tienda|armar tu tienda|arrancar|empezar|crear la tienda)/i;
const faqs = [
  { Pregunta: '¿Qué es NovaVision?', Respuesta: 'NovaVision es una plataforma SaaS de e-commerce 100% autogestionable. Creás tu tienda online en minutos con nuestro Design Studio: elegís un template, personalizás colores y cargás tus productos sin necesitar conocimientos técnicos ni intermediarios.', Categoría: 'General', Enlace: 'https://www.novavision.lat' },
  { Pregunta: '¿Qué diferencia a NovaVision de otras plataformas como Tiendanube o Shopify?', Respuesta: 'Tres cosas principales: 1) 0% comisión por venta, 2) SEO con Inteligencia Artificial incluido desde Growth, y 3) onboarding 100% self-serve. Además tenés envíos integrados con Andreani, OCA y Correo Argentino desde el plan Growth.', Categoría: 'General', Enlace: '' },
  { Pregunta: '¿Cuánto sale NovaVision? ¿Cuáles son los planes?', Respuesta: 'Tenemos 3 planes: Starter (USD 20/mes), Growth (USD 60/mes, recomendado) y Enterprise (USD 390/mes para alto volumen). Si pagás anual, te bonificamos 2 meses: Starter USD 200/año, Growth USD 600/año, Enterprise USD 3.500/año. Sin comisión por venta y sin costo de setup.', Categoría: 'Precios', Enlace: 'https://www.novavision.lat/precios' },
  { Pregunta: '¿Cobran comisión por venta?', Respuesta: 'No, NovaVision cobra 0% de comisión por venta. Solo pagás la suscripción mensual o anual de tu plan. Las únicas comisiones son las que cobra Mercado Pago por procesar los pagos de tus clientes.', Categoría: 'Precios', Enlace: '' },
  { Pregunta: '¿En qué moneda se cobra?', Respuesta: 'Los precios están en dólares (USD), pero el cobro se realiza en pesos argentinos (ARS) a través de Mercado Pago, usando un tipo de cambio de referencia.', Categoría: 'Precios', Enlace: '' },
  { Pregunta: '¿Qué incluye el plan Starter?', Respuesta: 'El plan Starter (USD 20/mes) incluye: 1 tienda activa, productos ilimitados, hasta 150 órdenes/mes, tu subdominio en novavision.lat, logo y banners, FAQs, redes sociales, envío manual o retiro en local, y acceso al AI Import Wizard (5 productos por carga).', Categoría: 'Starter', Enlace: '' },
  { Pregunta: '¿Qué incluye el plan Growth?', Respuesta: 'El plan Growth (USD 60/mes) incluye todo lo de Starter más: hasta 3 tiendas activas, 1.000 órdenes por mes, cupones, analytics, SEO con IA, envíos con Andreani, OCA y Correo Argentino, variantes de producto, config avanzada de pagos, soporte por tickets con SLA y AI Import Wizard (50 productos por carga).', Categoría: 'Growth', Enlace: '' },
  { Pregunta: '¿Qué incluye el plan Enterprise?', Respuesta: 'El plan Enterprise (USD 390/mes) es para alto volumen. Incluye todo lo de Growth más: hasta 10 tiendas activas, 10.000 órdenes por mes, carril dedicado, redirects SEO 301 o 302, importación masiva con IA, SLA contractual, soporte prioritario y opciones de infraestructura aislada.', Categoría: 'Enterprise', Enlace: '' },
  { Pregunta: '¿Cómo creo mi tienda? ¿Cobran setup?', Respuesta: 'No hay costo de setup. El proceso es 100% self-serve: entrás a novavision.lat/builder, elegís subdominio, subís logo, cargás productos, elegís template, personalizás colores, conectás Mercado Pago y dejás la tienda lista en minutos.', Categoría: 'Onboarding', Enlace: 'https://novavision.lat/builder' },
  { Pregunta: '¿Cuánto tardo en tener mi tienda online?', Respuesta: 'El wizard de configuración se completa en minutos. Después pasa por una revisión rápida del equipo y queda publicada y lista para vender.', Categoría: 'Onboarding', Enlace: '' },
  { Pregunta: '¿Cómo funciona el diseño? ¿Puedo cambiar los colores?', Respuesta: 'Sí. Hay 8 templates profesionales y más de 20 paletas prediseñadas. En el plan Growth podés crear paletas personalizadas con los colores de tu marca.', Categoría: 'Diseño', Enlace: '' },
  { Pregunta: '¿Puedo cambiar el template después de crear la tienda?', Respuesta: 'Sí, podés cambiar de template en cualquier momento desde el panel de administración sin perder productos ni configuraciones.', Categoría: 'Diseño', Enlace: '' },
  { Pregunta: '¿Qué métodos de pago incluye?', Respuesta: 'La plataforma tiene integración nativa con Mercado Pago. Tus clientes pueden pagar con tarjeta de crédito, débito, transferencia y efectivo. También podés configurar señas, quién absorbe la comisión y excluir métodos específicos.', Categoría: 'Pagos', Enlace: '' },
  { Pregunta: '¿Cómo funcionan los envíos?', Respuesta: 'En todos los planes podés configurar envío manual, retiro en local o coordinar por WhatsApp. Desde Growth hay integración automática con Andreani, OCA y Correo Argentino, y también podés ofrecer envío gratis desde cierto monto.', Categoría: 'Envíos', Enlace: '' },
  { Pregunta: '¿Qué es el SEO con Inteligencia Artificial?', Respuesta: 'Desde Growth tenés auditoría SEO con puntaje, meta titles y descriptions auto-generados, sitemap XML, datos estructurados para Google y un AI SEO Autopilot que optimiza textos con un clic.', Categoría: 'SEO', Enlace: '' },
  { Pregunta: '¿Puedo importar productos con Inteligencia Artificial?', Respuesta: 'Sí. El AI Import Wizard permite cargas asistidas por IA: Starter 5 por carga, Growth 50 y Enterprise 200.', Categoría: 'Productos', Enlace: '' },
  { Pregunta: '¿Puedo vender productos con variantes?', Respuesta: 'Sí, desde Growth podés crear variantes de producto con Option Sets como talle, color o material, y también usar guías de talles.', Categoría: 'Productos', Enlace: '' },
  { Pregunta: '¿Puedo crear cupones de descuento?', Respuesta: 'Sí, desde Growth. Podés crear cupones de porcentaje, monto fijo o envío gratis, definir vigencia y limitar usos.', Categoría: 'Cupones', Enlace: '' },
  { Pregunta: '¿Tienen período de prueba o trial gratuito?', Respuesta: 'No hay trial gratuito por defecto, pero sí pueden existir cupones promocionales con meses bonificados. Si querés probar la plataforma, consultanos por WhatsApp o email para ver si hay promos activas.', Categoría: 'Trial', Enlace: '' },
  { Pregunta: '¿Qué tipo de soporte ofrecen?', Respuesta: 'Starter incluye soporte por email. Growth agrega tickets con SLA e hilo de conversación. Enterprise suma soporte prioritario con tiempos de respuesta contractuales.', Categoría: 'Soporte', Enlace: '' },
  { Pregunta: '¿Puedo usar mi propio dominio?', Respuesta: 'En Starter la tienda funciona con subdominio gratuito. Desde Growth podés conectar tu propio dominio personalizado.', Categoría: 'Dominio', Enlace: '' },
  { Pregunta: '¿Tienen analytics o reportes?', Respuesta: 'Sí, desde Growth tenés analytics integrados y podés conectar Google Analytics 4 y Google Tag Manager desde el panel.', Categoría: 'Analytics', Enlace: '' },
  { Pregunta: '¿Cómo los puedo contactar?', Respuesta: 'Podés escribir por WhatsApp al +54 9 11 3930-6801, por email a info@novavision.lat o por este mismo chat.', Categoría: 'Contacto', Enlace: '' }
];
const queryText = String(inbound.normalized_text || '').toLowerCase().trim();
const normalizedWords = queryText.split(/\s+/).filter(word => word.length >= 2);
const faqMatches = faqs
  .map((faq) => {
    const pregunta = String(faq.Pregunta || '').toLowerCase();
    const respuesta = String(faq.Respuesta || '').toLowerCase();
    let score = 0;
    if (queryText && (pregunta.includes(queryText) || respuesta.includes(queryText))) score += 12;
    normalizedWords.forEach((word) => {
      if (pregunta.includes(word)) score += 2;
      if (respuesta.includes(word)) score += 1;
    });
    return { ...faq, score };
  })
  .filter((faq) => faq.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 3);
const faqContext = faqMatches.length > 0
  ? faqMatches.map(({ Pregunta, Respuesta, Enlace }) => {
      let line = `• ${Pregunta}\n${Respuesta}`;
      if (Enlace && String(Enlace).trim()) line += `\nMás info: ${Enlace}`;
      return line;
    }).join('\n\n')
  : '';
const priceFaq = faqs.find((faq) => String(faq.Pregunta || '').includes('¿Cuánto sale NovaVision?'));
return [{ json: {
  thread_id: $node['Append Inbound Event'].json.thread_id,
  contact_id: $node['Append Inbound Event'].json.contact_id,
  identity_id: $node['Append Inbound Event'].json.identity_id,
  lead_id: $node['Append Inbound Event'].json.lead_id,
  ai_engagement_score: Number($node['Append Inbound Event'].json.ai_engagement_score || 0),
  input_text: inbound.normalized_text,
  from_user_id: inbound.external_user_id,
  channel_account_id: inbound.channel_account_id,
  display_name: inbound.external_display_name || 'Instagram Lead',
  conversation_history: historyText,
  last_bot_message: lastBotMessage,
  builder_already_sent: botMessages.some(h => String(h.message_text || '').includes(builderUrl)),
  user_asked_price: priceRegex.test(String(inbound.normalized_text || '')),
  is_short_affirmation: shortAffirmationRegex.test(String(inbound.normalized_text || '').trim()),
  last_bot_offered_prices: offeredPriceRegex.test(lastBotMessage),
  last_bot_offered_builder: offeredBuilderRegex.test(lastBotMessage),
  faq_context: faqContext,
  faq_match_count: faqMatches.length,
  faq_price_answer: priceFaq?.Respuesta || ''
} }];

