const raw = $input.first().json;
let aiOutput;
try {
  const content = raw.message?.content || raw.choices?.[0]?.message?.content || '';
  aiOutput = JSON.parse(content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  aiOutput = { reply: 'Gracias por escribirnos. Un asesor te responde a la brevedad.', engagement_delta: 0, conversation_stage: 'INTRO', intent: 'human_request', should_notify_sales: true, reasoning: 'JSON parse failed' };
}
const prev = $node['Prepare AI Context'].json;
const validStages = ['INTRO', 'DISCOVERY', 'FOLLOWUP', 'CLOSING', 'DEMO_OFFERED', 'DEMO_BOOKED'];
const normalize = (text) => String(text || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/https?:\/\/\S+/g, ' ')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const builderUrl = 'https://novavision.lat/builder';
const pricesUrl = 'https://novavision.lat/precios';
const mainSiteUrl = 'https://novavision.lat';
const staticPriceAnswer = prev.faq_price_answer || 'Tenemos 3 planes públicos: Starter (USD 20/mes), Growth (USD 60/mes) y Enterprise (USD 390/mes para alto volumen). Si pagás anual hay bonificación de 2 meses.';
const priceFallback = `${staticPriceAnswer} Más detalle en ${pricesUrl}. Si querés avanzar, arrancás en ${builderUrl}.`;
const builderFallback = prev.builder_already_sent
  ? `Si querés avanzar, podés hacerlo directo en ${builderUrl}. Si preferís, te resumo cuál plan te conviene según cantidad de pedidos o tiendas.`
  : `NovaVision te sirve para tener tienda propia, catálogo claro y cobros integrados. Si querés arrancar, podés crearla en minutos desde ${builderUrl}.`;
let reply = String(aiOutput.reply || '').trim();
const normalizedReply = normalize(reply);
const normalizedLastBot = normalize(prev.last_bot_message);
const repeatedReply = !!normalizedReply && !!normalizedLastBot && (normalizedReply === normalizedLastBot || normalizedReply.includes(normalizedLastBot) || normalizedLastBot.includes(normalizedReply));
const askedPrice = !!prev.user_asked_price;
const mentionsBuilder = reply.includes(builderUrl);
const mentionsMainSite = reply.includes(mainSiteUrl);
const mentionsPrices = /(starter|growth|enterprise|usd|20/mes|60/mes|390/mes|precio|precios|plan|planes)/i.test(reply);
const shortAffirmation = !!prev.is_short_affirmation;
if (shortAffirmation && prev.last_bot_offered_prices && (!reply || repeatedReply || !mentionsPrices)) {
  reply = priceFallback;
  aiOutput.intent = aiOutput.intent || 'curious';
  aiOutput.conversation_stage = 'FOLLOWUP';
  aiOutput.reasoning = `${aiOutput.reasoning || ''} | short affirmation price fallback applied`.trim();
}
if (shortAffirmation && !reply && prev.last_bot_offered_builder) {
  reply = builderFallback;
  aiOutput.reasoning = `${aiOutput.reasoning || ''} | short affirmation builder fallback applied`.trim();
}
if (askedPrice && (!reply || repeatedReply || (mentionsBuilder && !mentionsMainSite) || !mentionsPrices)) {
  reply = priceFallback;
  aiOutput.intent = aiOutput.intent || 'curious';
  aiOutput.conversation_stage = 'FOLLOWUP';
  aiOutput.reasoning = `${aiOutput.reasoning || ''} | price fallback applied`.trim();
}
if (!askedPrice && (!reply || repeatedReply)) {
  reply = builderFallback;
  aiOutput.reasoning = `${aiOutput.reasoning || ''} | duplicate fallback applied`.trim();
}
reply = reply.substring(0, 300);
const engagementDelta = Math.max(-10, Math.min(20, parseInt(aiOutput.engagement_delta) || 0));
const nextStage = validStages.includes(aiOutput.conversation_stage) ? aiOutput.conversation_stage : 'INTRO';
const newScore = Math.max(0, Math.min(100, Number(prev.ai_engagement_score || 0) + engagementDelta));
const isHot = newScore >= 80 || !!aiOutput.should_notify_sales;
return [{ json: {
  ...prev,
  reply,
  new_score: newScore,
  new_stage: nextStage,
  intent: aiOutput.intent || 'unknown',
  should_notify_sales: !!aiOutput.should_notify_sales,
  is_hot: isHot,
  reasoning: aiOutput.reasoning || ''
} }];

